final:
module RefModule(
   input                clk,
   input                clr_n,
   input                en,
   input [31:0]         d,

   output reg [31:0]    q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or negedge clr_n or posedge dbg_halt)begin
        if(!clr_n) q <= 32'd0;
        else if(en) q <= d;
    end
endmodule
